const root = $input.first().json || {};
let body = root.body;
if (!body || typeof body !== 'object') {
  if (root.negocio_id != null) body = root;
  else body = {};
}
const negocio_id = String(body.negocio_id ?? '').trim();
const session_id = String(body.session_id ?? '').trim();
function uuidLike(s) {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(s);
}
const sidOk = session_id.length >= 6 && session_id.length <= 200 && /^[a-zA-Z0-9_-]+$/.test(session_id);
const valid = uuidLike(negocio_id) && sidOk;
let respuesta_texto = '';
if (!uuidLike(negocio_id)) {
  respuesta_texto = 'La petición no es válida (no se identifica el negocio). Recarga la página e inténtalo de nuevo.';
} else if (!sidOk) {
  respuesta_texto = 'La sesión no es válida. Recarga o abre de nuevo el chat.';
}
return [{ json: { entrada_valida: valid, respuesta_texto } }];

const v = $('Validar Entrada').first().json;
return [{ json: {
  respuesta_texto: v.respuesta_texto || 'No se ha podido procesar la petición. Vuelve a intentarlo.',
  entrada_ok: false
} }];

let data = [];
try {
  const raw = $input.first()?.json;
  if (Array.isArray(raw)) {
    data = raw;
  } else if (raw && Array.isArray(raw.data)) {
    data = raw.data;
  } else if (raw && typeof raw === 'object') {
    data = [raw];
  }
} catch(e) { data = []; }
return [{ json: { data } }];

try {
const wh = $('Webhook Cursor').first().json.body || {};
let mensajeUser = String(wh.mensaje ?? '');
if (mensajeUser.length > 12000) mensajeUser = mensajeUser.slice(0, 12000);
let negocio = $('Datos Negocio').first().json;
if (Array.isArray(negocio)) negocio = negocio[0] || {};
if (!negocio || typeof negocio !== 'object') negocio = {};

let hist = $('Normalizar Historial').first().json.data;
if (!Array.isArray(hist)) hist = [];
hist = hist.slice().reverse();

let estadoPrev = {};
let cancelacionPendiente = null;
try {
  const items = $('Cargar Estado Cita').all() || [];
  for (const it of items) {
    const j = it?.json;
    if (!j) continue;
    if (Array.isArray(j) && j.length) {
      const row = j[0];
      if (row?.datos_cita && typeof row.datos_cita === 'object') estadoPrev = row.datos_cita;
      if (row?.cancelacion_pendiente && typeof row.cancelacion_pendiente === 'object') cancelacionPendiente = row.cancelacion_pendiente;
      break;
    }
    if (j?.datos_cita && typeof j.datos_cita === 'object') estadoPrev = j.datos_cita;
    if (j?.cancelacion_pendiente && typeof j.cancelacion_pendiente === 'object') cancelacionPendiente = j.cancelacion_pendiente;
    if (j?.datos_cita || j?.cancelacion_pendiente) break;
  }
} catch(e) { estadoPrev = {}; cancelacionPendiente = null; }

function sanePend(p) {
  if (!p || typeof p !== 'object' || Array.isArray(p)) return null;
  const ex = !!p.esperando_confirmacion;
  const ec = !!p.esperando_contacto;
  if (ex && ec) return null;
  if (ex && (!Array.isArray(p.citas) || !p.citas.length)) return null;
  return p;
}
cancelacionPendiente = sanePend(cancelacionPendiente);

const hoyISO = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Madrid' });
const hoyDiaSemana = new Date().toLocaleDateString('es-ES', { timeZone: 'Europe/Madrid', weekday: 'long' });
const yearActual = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' }).slice(0,4);

const sysPrompt = [
  `Eres el asistente del negocio \"${negocio.nombre || ''}\".`,
  negocio.prompt_personalizado || negocio.prompt_sistema || '',
  negocio.descripcion ? `Sobre el negocio: ${negocio.descripcion}` : '',
  negocio.horario ? `Horario: ${negocio.horario}` : '',
  negocio.direccion ? `Dirección: ${negocio.direccion}` : '',
  '',
  'Reglas:',
  '- Sé claro, breve y útil.',
  '- Si el cliente quiere reservar/agendar/pedir cita: pregúntale UNO A UNO los datos que falten en este orden: día, hora, nombre, apellido, teléfono, email.',
  '- NUNCA confirmes ni menciones una fecha o hora que el cliente NO haya dicho explícitamente.',
  '- Si ya tienes un dato confirmado por el cliente en el historial, no lo vuelvas a pedir.',
  '- Si el cliente dice que ya dio nombre o datos y el HISTORIAL de esta conversación contiene ese nombre o una confirmación previa con sus datos, reconócelo y sigue con la reserva; no digas que no tienes acceso a información previa.',
  '- Si solo conversa o pregunta, responde con naturalidad.',
  (cancelacionPendiente && (cancelacionPendiente.esperando_confirmacion || cancelacionPendiente.esperando_contacto)) ? '- Hay una anulación de cita en curso en esta conversación: mantén el foco en ese proceso hasta que el cliente confirme, rechace o abandone.' : '',
  `- Hoy es ${hoyISO} (${hoyDiaSemana}). Estamos en el año ${yearActual}.`
].filter(Boolean).join('\n');

const messages = [{ role: 'system', content: sysPrompt }];
for (const m of hist) {
  if (!m || !m.contenido) continue;
  if (m.rol === 'user' || m.rol === 'assistant') {
    messages.push({ role: m.rol, content: String(m.contenido) });
  }
}
messages.push({ role: 'user', content: mensajeUser });

const historialTexto = hist
  .map(m => `${m.rol === 'user' ? 'Cliente' : 'Asistente'}: ${m.contenido}`)
  .join('\n');

return [{
  json: {
    negocio_id: wh.negocio_id,
    session_id: wh.session_id,
    mensaje: mensajeUser,
    negocio,
    historial: hist,
    historialTexto,
    estadoPrev,
    cancelacionPendiente,
    system_prompt: sysPrompt,
    messages,
    hoy: hoyISO,
    yearActual
  }
}];

} catch (e) {
  const wh = $('Webhook Cursor').first().json.body || {};
  const msg = String(wh.mensaje ?? '').slice(0, 12000);
  const hoyISO = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Madrid' });
  const yearActual = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' }).slice(0, 4);
  const sys = 'Eres un asistente amable y profesional. Responde con una sola frase corta: discúlpate por un problema técnico momentáneo y pide que el usuario repita el mensaje en unos segundos. No inventes datos del negocio ni citas.';
  return [{
    json: {
      negocio_id: wh.negocio_id,
      session_id: wh.session_id,
      mensaje: msg,
      negocio: {},
      historial: [],
      historialTexto: '',
      estadoPrev: {},
      cancelacionPendiente: null,
      system_prompt: sys,
      messages: [{ role: 'system', content: sys }, { role: 'user', content: msg || '(mensaje vacío)' }],
      hoy: hoyISO,
      yearActual,
      _contexto_degradado: true
    }
  }];
}

try {
const ctx = $('Preparar Contexto').first().json;
const pend = ctx.cancelacionPendiente || {};
const raw = String(ctx.mensaje || '').trim();
const msg = raw.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');

function isConfirm(s) {
  if (!s) return false;
  if (/^(si|sip|sisi|ok|vale|claro|genial|perfecto|adelante|exacto|correcto|efectivo|por\s*supuesto|de\s*acuerdo|confirmo|confirmar)\b/i.test(s)) return true;
  if (/^\s*(si|ok|vale)(\s*[!\.\s]*)?$/i.test(s)) return true;
  return false;
}
function isDeny(s) {
  if (!s) return false;
  if (/^(no|nop|nope|mejor\s*no|dejalo|dejemoslo|negativo|para\s+nada|no\s+cancel)\b/i.test(s)) return true;
  if (/^\s*no(\s+gracias)?\s*[!.?\s]*$/i.test(s)) return true;
  return false;
}

function pareceNuevaReservaSinCancelar(s) {
  if (!s) return false;
  if (/\b(cancelar|anular|eliminar|dar\s+de\s+baja|no\s+podre\s+acudir)\b/.test(s)) return false;
  if (/\b(el\s+)?(lunes|martes|miercoles|jueves|viernes|sabado|domingo)\b/.test(s) && /\d/.test(s)) return true;
  if (/\b\d{1,2}\s+de\s+(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\b/.test(s)) return true;
  if (/\b(manana|pasado\s+manana|hoy)\b/.test(s) && /\b(las\s+)?\d{1,2}\b/.test(s)) return true;
  if (/\ba\s+las\s+\d{1,2}\b/.test(s)) return true;
  return false;
}

function quiereSalirBusquedaContacto(s) {
  if (/\bquiero\s+pedir(\s+cita)?\b/i.test(s)) return true;
  return /\b(olvidalo|dejalo|paso|paso\s+de\s+esto|me\s+rinde|otra\s+cosa|cambio\s+de\s+tema|cambio\s+de\s+idea|ya\s+no|no\s+quiero\s+cancelar|mejor\s+no\s+cancelo|quiero\s+reservar|queria\s+reservar|quisiera\s+reservar|queria\s+una\s+cita|solo\s+queria|pedir\s+cita|hacer\s+cita|reservar|agendar|cita\s+nueva|nada\s+dejalo|cancela\s+eso\s+no)\b/i.test(s);
}

function variantesTelefono(text) {
  let d = String(text || '').replace(/\D/g, '');
  const out = [];
  const add = (x) => { if (x && !out.includes(x)) out.push(x); };
  if (d.startsWith('0034')) d = d.slice(4);
  while (d.startsWith('34') && d.length > 11) d = d.slice(2);
  if (/^0+[6-9]/.test(d)) d = d.replace(/^0+/, '');
  if (d.length >= 9) add(d.slice(-9));
  if (d.length >= 10) add(d.slice(-10));
  add(d);
  if (d.length >= 11 && d.startsWith('34')) add(d.slice(2));
  return out.filter(Boolean);
}

function extraerContacto(text) {
  const emails = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi) || [];
  const email = emails.length ? emails[0].toLowerCase().trim() : null;
  const allDigits = text.replace(/\D/g, '');
  const vars = variantesTelefono(allDigits);
  const telefono = vars.find(t => t.length === 9 && /^[6-9]/.test(t)) || vars.find(t => t.length >= 9) || null;
  const telefonoVariantes = telefono ? [...new Set(vars.filter(v => v.length >= 8))] : [];
  return { email, telefono, telefonoVariantes, digitCount: allDigits.length };
}

if (pend.esperando_confirmacion) {
  if (!Array.isArray(pend.citas) || !pend.citas.length) {
    return [{ json: { action: 'abortar_cancelacion', negocio_id: ctx.negocio_id, session_id: ctx.session_id, respuesta_abort_override: 'La confirmación de cancelación ya no es válida. Si quieres anular una cita, di de nuevo que deseas cancelar.' } }];
  }
  if (isConfirm(msg)) {
    return [{ json: { action: 'ejecutar_cancelacion', citas: pend.citas, negocio_id: ctx.negocio_id, session_id: ctx.session_id } }];
  }
  if (isDeny(msg)) {
    return [{ json: { action: 'abortar_cancelacion', negocio_id: ctx.negocio_id, session_id: ctx.session_id } }];
  }
  return [{ json: { action: 'repetir_confirmacion', negocio_id: ctx.negocio_id, session_id: ctx.session_id, respuesta_texto: 'Para anular la(s) cita(s) que te indiqué, responde SÍ si confirmas la anulación o NO si quieres conservarla. Si necesitas otra cosa, responde NO y lo vemos.' } }];
}

if (pend.esperando_contacto) {
  if (pareceNuevaReservaSinCancelar(msg)) {
    return [{ json: { action: 'abortar_cancelacion', negocio_id: ctx.negocio_id, session_id: ctx.session_id } }];
  }
  if (quiereSalirBusquedaContacto(msg)) {
    return [{ json: { action: 'abortar_cancelacion', negocio_id: ctx.negocio_id, session_id: ctx.session_id } }];
  }
  const { email, telefono, telefonoVariantes, digitCount } = extraerContacto(raw);
  if (email || telefono) {
    return [{ json: { action: 'buscar_citas_contacto', negocio_id: ctx.negocio_id, session_id: ctx.session_id, telefono, telefonoVariantes, email } }];
  }
  if (digitCount > 0 && digitCount < 9) {
    return [{ json: { action: 'repetir_contacto', negocio_id: ctx.negocio_id, session_id: ctx.session_id, respuesta_texto: 'El teléfono parece incompleto (en España suelen ser 9 cifras). Revísalo o escribe el email con el que reservaste.' } }];
  }
  return [{ json: { action: 'repetir_contacto', negocio_id: ctx.negocio_id, session_id: ctx.session_id, respuesta_texto: 'No he encontrado un teléfono o email claro. Escríbelo como al reservar (ej: 612345678, +34 612 34 56 78 o tu correo).' } }];
}

return [{ json: { action: 'continuar', negocio_id: ctx.negocio_id, session_id: ctx.session_id } }];
} catch (err) {
  const wh = $('Webhook Cursor').first().json.body || {};
  return [{ json: { action: 'continuar', negocio_id: String(wh.negocio_id || ''), session_id: String(wh.session_id || '') } }];
}

const ev = $('Evaluar Confirmación Cancelación').first().json;
const nid = ev.negocio_id;
const parts = [];
const tels = Array.isArray(ev.telefonoVariantes) && ev.telefonoVariantes.length ? ev.telefonoVariantes : (ev.telefono ? [ev.telefono] : []);
for (const t of tels) {
  if (!t) continue;
  parts.push('telefono.eq.' + t);
  parts.push('cliente_telefono.eq.' + t);
}
if (ev.email) parts.push('email.eq.' + ev.email);
if (!parts.length) {
  return [{ json: { requestUrl: 'https://dovoggkeoguqtscmsjna.supabase.co/rest/v1/citas?negocio_id=eq.' + nid + '&id=eq.00000000-0000-0000-0000-000000000000&estado=in.(pendiente,confirmada)&limit=1&select=id' } }];
}
const orClause = '(' + parts.join(',') + ')';
const url = 'https://dovoggkeoguqtscmsjna.supabase.co/rest/v1/citas?negocio_id=eq.' + nid + '&estado=in.(pendiente,confirmada)&order=fecha_hora.asc&limit=20&select=id,fecha_hora,nombre,apellido,nombre_cliente,telefono,email,servicio&or=' + encodeURIComponent(orClause);
return [{ json: { requestUrl: url } }];

const j = $input.first().json;
if (j && typeof j === 'object' && !Array.isArray(j) && j.message && j.code != null && !j.id) {
  return [{ json: { __rows: [], origenBusqueda: 'contacto', errorApi: true } }];
}
let rawRows = [];
if (Array.isArray(j)) rawRows = j.filter(r => r && r.id);
else if (j && j.id && j.fecha_hora) rawRows = [j];
return [{ json: { __rows: rawRows, origenBusqueda: 'contacto', errorApi: false } }];

const ev = $('Evaluar Confirmación Cancelación').first().json;
const respuesta_texto = ev.respuesta_abort_override || 'De acuerdo, no he anulado ninguna cita. ¿En qué más puedo ayudarte?';
return [{ json: { negocio_id: ev.negocio_id, session_id: ev.session_id, respuesta_texto } }];

const j = $input.first().json;
const raw = String($('Preparar Contexto').first().json.mensaje || '').trim();
const msg = raw.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const prev = $('Preparar Contexto').first().json.estadoPrev || {};
const histPc = Array.isArray($('Preparar Contexto').first().json.historial) ? $('Preparar Contexto').first().json.historial : [];

function ultimoContenidoAsistente(arr) {
  for (let i = arr.length - 1; i >= 0; i--) {
    const m = arr[i];
    if (!m || !m.contenido) continue;
    const rol = String(m.rol || '').toLowerCase();
    if (rol === 'assistant' || rol === 'asistente') return String(m.contenido);
  }
  return '';
}

function invitacionAReservarOtra(texto) {
  const t = String(texto || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (!t) return false;
  if (/\breservar\s+otra\b/.test(t)) return true;
  if (/\botra\s+cita\b/.test(t)) return true;
  if (/\bd[ií]melo\s+cuando\s+quieras\b/.test(t)) return true;
  if (/\bcuando\s+quieras\b/.test(t) && /\breserv/.test(t)) return true;
  if (/he\s+anulad\w+/.test(t) && /\breserv/.test(t)) return true;
  if (/\bsi\s+quieres\s+reservar\b/.test(t)) return true;
  return false;
}

function afirmacionCortaReserva(r) {
  const x = String(r || '').trim();
  if (!x || x.length > 28) return false;
  const n = x.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (/^(si|sip|sii|vale|ok|okay|claro|perfecto|adelante|genial|bueno|vamos|yes)\b/.test(n)) return true;
  if (/^(si|ok|vale)[\s!.?]*$/i.test(x)) return true;
  return false;
}

function pareceNuevaReservaSinCancelar(s) {
  if (!s) return false;
  if (/\b(cancelar|anular|eliminar|dar\s+de\s+baja|no\s+podre\s+acudir)\b/.test(s)) return false;
  if (/\b(el\s+)?(lunes|martes|miercoles|jueves|viernes|sabado|domingo)\b/.test(s) && /\d/.test(s)) return true;
  if (/\b\d{1,2}\s+de\s+(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\b/.test(s)) return true;
  if (/\b(manana|pasado\s+manana|hoy)\b/.test(s) && /\b(las\s+)?\d{1,2}\b/.test(s)) return true;
  if (/\ba\s+las\s+\d{1,2}\b/.test(s)) return true;
  return false;
}

function pareceEmailEnTexto(r) {
  return /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i.test(r);
}

function pareceSoloTelefono(r) {
  const t = r.trim();
  if (!t) return false;
  const d = t.replace(/\D/g, '');
  if (d.length < 9 || d.length > 15) return false;
  return /^[+\d()[\]\s.-]+$/.test(t);
}

function hayCitaEnSesion(p) {
  return !!(p && p.fecha && String(p.fecha).trim() && p.hora && String(p.hora).trim());
}

function faltaAlgunDatoContacto(p) {
  if (!hayCitaEnSesion(p)) return false;
  return !(p.nombre && p.apellido && p.telefono && p.email);
}

function pareceRespuestaNombreApellido(r, s) {
  if (!r || pareceEmailEnTexto(r) || /\d/.test(r)) return false;
  if (/\b(cancelar|anular|hola|gracias|vale|cuanto|donde|como|cuesta|quiero|necesito|precio|horario|servicios)\b/.test(s)) return false;
  const parts = r.trim().split(/\s+/).filter(Boolean);
  if (parts.length < 2 || parts.length > 4) return false;
  const ok = /^[a-zA-ZáéíóúÁÉÍÓÚñÑüÜ'.-]+$/;
  if (!parts.every(w => ok.test(w))) return false;
  const stop = new Set(['cuanto','cuesta','donde','como','hola','gracias','vale','si','no','bien','adios','buenas','precio','horario','quiero','necesito','para','cita','reservar']);
  const w0 = parts[0].toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  if (stop.has(w0)) return false;
  return true;
}

const ultimoAsis = ultimoContenidoAsistente(histPc);
let forzarReserva = pareceNuevaReservaSinCancelar(msg);
if (!forzarReserva && invitacionAReservarOtra(ultimoAsis) && afirmacionCortaReserva(raw)) forzarReserva = true;
if (!forzarReserva && faltaAlgunDatoContacto(prev) && !/\b(cancelar|anular)\b/.test(msg)) {
  if (pareceSoloTelefono(raw) || pareceEmailEnTexto(raw)) forzarReserva = true;
  else if ((!prev.nombre || !prev.apellido) && pareceRespuestaNombreApellido(raw, msg)) forzarReserva = true;
}

let txt = (j.choices?.[0]?.message?.content || '').trim();
if (forzarReserva) txt = 'RESERVAR';
const base = j.choices?.[0] || { message: { role: 'assistant', content: '' } };
const ch0 = { ...base, message: { ...base.message, content: txt } };
return [{ json: { ...j, choices: [ch0] } }];

const items = $input.all() || [];
const ctx = $('Preparar Contexto').first().json;
let rawRows = [];
let origenBusqueda = 'sesion';
let errorApiWrapped = false;

for (const it of items) {
  const j = it?.json;
  if (!j) continue;
  if (j.origenBusqueda === 'contacto') {
    rawRows = Array.isArray(j.__rows) ? j.__rows.filter(r => r && r.id) : [];
    origenBusqueda = 'contacto';
    errorApiWrapped = !!j.errorApi;
    break;
  }
  if (Array.isArray(j)) {
    rawRows = j.filter(r => r && r.id);
    break;
  }
  if (j.id && j.fecha_hora) {
    rawRows = [j];
    break;
  }
  if (j.message && j.code != null && !j.id && !Array.isArray(j)) {
    return [{ json: { negocio_id: ctx.negocio_id, session_id: ctx.session_id, encontrada: false, origenBusqueda: 'sesion', flujo_sin_citas: 'error_api', respuesta_texto: 'No pude consultar tus citas ahora mismo (fallo temporal). Prueba otra vez en unos segundos o di de nuevo que quieres cancelar.', cancelacion_pendiente_payload: null } }];
  }
}

if (errorApiWrapped && origenBusqueda === 'contacto') {
  return [{ json: { negocio_id: ctx.negocio_id, session_id: ctx.session_id, encontrada: false, origenBusqueda: 'contacto', flujo_sin_citas: 'error_api', respuesta_texto: 'No pude completar la búsqueda por teléfono o email. Inténtalo otra vez en un momento.', cancelacion_pendiente_payload: { esperando_contacto: true } } }];
}

const seen = new Set();
rawRows = rawRows.filter(r => {
  if (!r || !r.id) return false;
  if (seen.has(r.id)) return false;
  seen.add(r.id);
  return true;
});
rawRows.sort((a, b) => String(a.fecha_hora || '').localeCompare(String(b.fecha_hora || '')));

if (!rawRows.length) {
  let flujo_sin_citas = null;
  let respuesta_texto = '';
  let cancelacion_pendiente_payload = null;
  if (origenBusqueda === 'sesion') {
    flujo_sin_citas = 'pedir_contacto';
    cancelacion_pendiente_payload = { esperando_contacto: true };
    respuesta_texto = 'No veo ninguna cita enlazada a esta conversación (por ejemplo si reservaste en otro dispositivo o ventana). Para localizarla, escribe el mismo teléfono o email que usaste al reservar.';
